#!/usr/bin/env node
// E2E tests -- auto-generated by Clear compiler
// Run: node test.js
// Requires: server running on localhost:3000

const BASE = process.env.TEST_URL || "http://localhost:3000";
let passed = 0, failed = 0;
let _emailCounter = 0;
let _uniqueCounter = 0;
function _uniqueEmail() { return "test" + (++_emailCounter) + "@example.com"; }
function _uniqueText(base) { return base + "_" + (++_uniqueCounter); }

// Note: for clean re-runs, delete clear-data.json before starting the server
// unique constraints may cause 500s if stale data exists from a previous run

// Generate a test auth token using the same runtime as the server
const auth = require("./clear-runtime/auth");
const TEST_TOKEN = auth.createToken({ id: 1, role: "admin", email: "test@test.com" });
const AUTH_HEADERS = { "Authorization": "Bearer " + TEST_TOKEN, "Content-Type": "application/json" };

async function test(name, fn) {
  try {
    await fn();
    passed++;
    console.log("PASS:", name);
  } catch (err) {
    failed++;
    console.log("FAIL:", name, "-", err.message);
  }
}

function assert(condition, msg) { if (!condition) throw new Error(msg); }

async function run() {
  await test("GET /api/services returns 200", async () => {
    const r = await fetch(BASE + "/api/services");
    assert(r.status === 200, "Expected 200, got " + r.status);
  });

  await test("GET /api/clients returns 200", async () => {
    const r = await fetch(BASE + "/api/clients");
    assert(r.status === 200, "Expected 200, got " + r.status);
  });

  await test("GET /api/bookings returns 200", async () => {
    const r = await fetch(BASE + "/api/bookings");
    assert(r.status === 200, "Expected 200, got " + r.status);
  });

  await test("POST /api/services with valid data returns 201", async () => {
    const payload = {"name":"Test value"};
    payload["name"] = _uniqueText("name");
    const r = await fetch(BASE + "/api/services", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Response should have an id");
  });

  await test("POST /api/services with no body returns 400", async () => {
    const r = await fetch(BASE + "/api/services", { method: "POST", headers: { "Authorization": "Bearer " + TEST_TOKEN } });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/services with empty required field returns 400", async () => {
    const r = await fetch(BASE + "/api/services", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify({ name: "" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/clients with valid data returns 201", async () => {
    const payload = {"name":"Test value","email":"test@example.com"};
    payload["name"] = _uniqueText("name");
    payload["email"] = _uniqueEmail();
    const r = await fetch(BASE + "/api/clients", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Response should have an id");
  });

  await test("POST /api/clients with no body returns 400", async () => {
    const r = await fetch(BASE + "/api/clients", { method: "POST", headers: { "Authorization": "Bearer " + TEST_TOKEN } });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/clients with empty required field returns 400", async () => {
    const r = await fetch(BASE + "/api/clients", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify({ name: "" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/bookings with valid data returns 201", async () => {
    const payload = {"client_name":"Test value","service_name":"Test value","date":"Test value","time":"Test value"};
    payload["client_name"] = _uniqueText("client_name");
    payload["service_name"] = _uniqueText("service_name");
    payload["date"] = _uniqueText("date");
    payload["time"] = _uniqueText("time");
    const r = await fetch(BASE + "/api/bookings", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Response should have an id");
  });

  await test("POST /api/bookings with no body returns 400", async () => {
    const r = await fetch(BASE + "/api/bookings", { method: "POST", headers: { "Authorization": "Bearer " + TEST_TOKEN } });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/bookings with empty required field returns 400", async () => {
    const r = await fetch(BASE + "/api/bookings", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify({ client_name: "" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("DELETE /api/services/:id without auth returns 401", async () => {
    const r = await fetch(BASE + "/api/services/999", { method: "DELETE" });
    assert(r.status === 401, "Expected 401, got " + r.status);
  });

  await test("DELETE /api/bookings/:id without auth returns 401", async () => {
    const r = await fetch(BASE + "/api/bookings/999", { method: "DELETE" });
    assert(r.status === 401, "Expected 401, got " + r.status);
  });

  await test("POST /api/services strips unknown fields (mass assignment protection)", async () => {
    const payload = { ...{"name":"Test value"}, admin: true, role: "superuser" };
    payload["name"] = _uniqueText("name");
    const r = await fetch(BASE + "/api/services", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.admin === undefined, "admin field should have been stripped");
    assert(data.role === undefined, "role field should have been stripped");
  });

  await test("GET /api/services returns created records after POST", async () => {
    const r = await fetch(BASE + "/api/services");
    const data = await r.json();
    assert(Array.isArray(data), "Expected array");
    assert(data.length > 0, "Expected at least one record (from earlier POST test)");
  });

  await test("GET / serves HTML", async () => {
    const r = await fetch(BASE + "/");
    assert(r.status === 200, "Expected 200, got " + r.status);
    const html = await r.text();
    assert(html.includes("<!DOCTYPE html>"), "Expected HTML document");
  });

  console.log("");
  console.log("Results:", passed, "passed,", failed, "failed");
  process.exit(failed > 0 ? 1 : 0);
}

run();